import { ChartAxis } from '~/queries/schema/schema-general'

export interface QueryConfig {
    dateFrom: string
    dateTo: string
    requestNameBreakdownEnabled: boolean
    requestNameFilter: string[]
}

const createRequestNameFilterClause = (requestNameFilter: string[]): string => {
    if (requestNameFilter.length === 0) {
        return ''
    }

    const escapedNames = requestNameFilter.map((name) => `'${name.replace(/'/g, "''")}'`).join(', ')
    return `and name in (${escapedNames})`
}

export const createExpensiveQueriesColumns = (requestNameBreakdownEnabled: boolean): ChartAxis[] => {
    const baseColumns = [
        {
            column: 'query_start_time',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query_duration_ms',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'read_tb',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'cpu_sec',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'created_by',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
    ]

    return requestNameBreakdownEnabled
        ? [
              ...baseColumns,
              {
                  column: 'name',
                  settings: { formatting: { prefix: '', suffix: '' } },
              },
          ]
        : baseColumns
}

export const createLast20QueriesColumns = (requestNameBreakdownEnabled: boolean): ChartAxis[] => {
    const baseColumns = [
        {
            column: 'finished_at',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query_duration_ms',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'created_by',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
    ]

    return requestNameBreakdownEnabled
        ? [
              ...baseColumns,
              {
                  column: 'name',
                  settings: { formatting: { prefix: '', suffix: '' } },
              },
          ]
        : baseColumns
}

export const createFailedQueriesColumns = (): ChartAxis[] => {
    return [
        {
            column: 'finished_at',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query_id',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'endpoint',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'query_duration_ms',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'name',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'read_tb',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'human_readable_read_size',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'cpu_sec',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'memory_usage',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'status',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'exception_code',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
        {
            column: 'exception_name',
            settings: { formatting: { prefix: '', suffix: '' } },
        },
    ]
}

export const createApiQueriesCountQuery = ({
    dateFrom,
    dateTo,
    requestNameBreakdownEnabled,
    requestNameFilter,
}: QueryConfig): string => `
    select 
        event_date, 
        ${requestNameBreakdownEnabled ? 'name,' : ''} 
        count(1) as number_of_queries
    from query_log
    where is_personal_api_key_request 
        and event_date >= '${dateFrom}' 
        and event_date <= '${dateTo}'
        ${createRequestNameFilterClause(requestNameFilter)}
    group by event_date ${requestNameBreakdownEnabled ? ', name' : ''}
    order by event_date asc ${requestNameBreakdownEnabled ? ', name asc' : ''}`

export const createApiReadTbQuery = ({
    dateFrom,
    dateTo,
    requestNameBreakdownEnabled,
    requestNameFilter,
}: QueryConfig): string => `
    select 
        event_date, 
        ${requestNameBreakdownEnabled ? 'name,' : ''}
        sum(read_bytes)/1e12 as read_tb
    from query_log
    where 
        is_personal_api_key_request 
        and event_date >= '${dateFrom}' 
        and event_date <= '${dateTo}'
        ${createRequestNameFilterClause(requestNameFilter)}
    group by event_date ${requestNameBreakdownEnabled ? ', name' : ''}
    order by event_date asc ${requestNameBreakdownEnabled ? ', name asc' : ''}`

export const createApiCpuSecondsQuery = ({
    dateFrom,
    dateTo,
    requestNameBreakdownEnabled,
    requestNameFilter,
}: QueryConfig): string => `
    select 
        event_date, 
        ${requestNameBreakdownEnabled ? 'name,' : ''}
        sum(cpu_microseconds)/1e6 as cpu_sec
    from query_log
    where 
        is_personal_api_key_request 
        and event_date >= '${dateFrom}' 
        and event_date <= '${dateTo}'
        ${createRequestNameFilterClause(requestNameFilter)}
    group by event_date ${requestNameBreakdownEnabled ? ', name' : ''}
    order by event_date asc ${requestNameBreakdownEnabled ? ', name asc' : ''}`

export const createApiQueriesPerKeyQuery = ({ dateFrom, dateTo }: QueryConfig): string => `
    select 
        event_date, 
        api_key_label, 
        count(1) as total_queries
    from query_log 
    where 
        event_date >= '${dateFrom}'
        and event_date <= '${dateTo}'
        and is_personal_api_key_request
    group by event_date, api_key_label
    order by event_date`

export const createLast20QueriesQuery = ({
    dateFrom,
    dateTo,
    requestNameBreakdownEnabled,
    requestNameFilter,
}: QueryConfig): string => `
    select 
        event_time as finished_at, 
        ${requestNameBreakdownEnabled ? 'name,' : ''}
        query, 
        query_duration_ms, 
        api_key_label,
        created_by 
    from query_log
    where
        is_personal_api_key_request
        and event_date >= '${dateFrom}'
        and event_date <= '${dateTo}'
        ${createRequestNameFilterClause(requestNameFilter)}
    order by event_time desc
    limit 20`

export const createExpensiveQueriesQuery = ({
    dateFrom,
    dateTo,
    requestNameBreakdownEnabled,
    requestNameFilter,
}: QueryConfig): string => `
    select 
        query_start_time, 
        ${requestNameBreakdownEnabled ? 'name,' : ''}
        query,
        query_duration_ms,
        api_key_label,
        read_bytes / 1e12 as read_tb,
        formatReadableSize(read_bytes) as human_readable_read_size,
        cpu_microseconds / 1e6 as cpu_sec,
        memory_usage,
        created_by
    from query_log
    where 
        is_personal_api_key_request
        and event_date >= '${dateFrom}'
        and event_date <= '${dateTo}'
        ${createRequestNameFilterClause(requestNameFilter)}
    order by read_tb desc, event_time desc
    limit 25`

export const createFailedQueriesQuery = ({ dateFrom, dateTo }: QueryConfig): string => `
    select 
        event_time as finished_at,
        query_id,
        endpoint,
        query, 
        query_duration_ms,
        name,
        read_bytes / 1e12 as read_tb,
        formatReadableSize(read_bytes) as human_readable_read_size,
        cpu_microseconds / 1e6 as cpu_sec,
        memory_usage,
        status,
        exception_code, 
        exception_name,
    from query_log 
    where 
        is_personal_api_key_request
        and exception_code != 0 
        and event_date >= '${dateFrom}'
        and event_date <= '${dateTo}'
    order by read_tb desc, event_time desc
    limit 25`

import { actions, connect, kea, key, path, props, reducers, selectors } from 'kea'
import { router } from 'kea-router'

import { dayjs } from 'lib/dayjs'
import { tabAwareActionToUrl } from 'lib/logic/scenes/tabAwareActionToUrl'
import { tabAwareUrlToAction } from 'lib/logic/scenes/tabAwareUrlToAction'
import { dateStringToDayJs } from 'lib/utils'
import { urls } from 'scenes/urls'

import {
    EndpointsUsageBreakdown,
    EndpointsUsageOverviewQuery,
    EndpointsUsageTableQuery,
    EndpointsUsageTrendsQuery,
    NodeKind,
} from '~/queries/schema/schema-general'
import { EndpointType, IntervalType } from '~/types'

import { endpointsLogic } from './endpointsLogic'
import type { endpointsUsageLogicType } from './endpointsUsageLogicType'

export const INITIAL_DATE_FROM = '-7d'
export const INITIAL_DATE_TO = null as string | null
export const INITIAL_INTERVAL: IntervalType = 'day'

export interface EndpointsUsageLogicProps {
    tabId: string
}

export const endpointsUsageLogic = kea<endpointsUsageLogicType>([
    path(['products', 'endpoints', 'frontend', 'endpointsUsageLogic']),
    props({} as EndpointsUsageLogicProps),
    key((props) => props.tabId),
    connect(({ tabId }: EndpointsUsageLogicProps) => ({
        values: [endpointsLogic({ tabId }), ['allEndpoints', 'allEndpointsLoading']],
    })),

    actions({
        setDates: (dateFrom: string | null, dateTo: string | null) => ({ dateFrom, dateTo }),
        setEndpointFilter: (endpointFilter: string[]) => ({ endpointFilter }),
        setMaterializationType: (materializationType: 'materialized' | 'inline' | null) => ({ materializationType }),
        setInterval: (interval: IntervalType) => ({ interval }),
        setBreakdownBy: (breakdownBy: EndpointsUsageBreakdown | null) => ({ breakdownBy }),
    }),

    reducers({
        dateFilter: [
            {
                dateFrom: INITIAL_DATE_FROM,
                dateTo: INITIAL_DATE_TO,
            } as { dateFrom: string | null; dateTo: string | null },
            {
                setDates: (_, { dateFrom, dateTo }) => ({ dateFrom, dateTo }),
            },
        ],
        endpointFilter: [
            [] as string[],
            {
                setEndpointFilter: (_, { endpointFilter }) => endpointFilter,
            },
        ],
        materializationType: [
            null as 'materialized' | 'inline' | null,
            {
                setMaterializationType: (_, { materializationType }) => materializationType,
            },
        ],
        interval: [
            INITIAL_INTERVAL as IntervalType,
            {
                setInterval: (_, { interval }) => interval,
            },
        ],
        breakdownBy: [
            null as EndpointsUsageBreakdown | null,
            {
                setBreakdownBy: (_, { breakdownBy }) => breakdownBy,
            },
        ],
    }),

    selectors({
        endpointNames: [
            (s) => [s.allEndpoints],
            (allEndpoints: EndpointType[]): string[] =>
                allEndpoints
                    .filter((e) => e.last_executed_at)
                    .map((e) => e.name)
                    .sort(),
        ],
        endpointNamesLoading: [(s) => [s.allEndpointsLoading], (loading: boolean): boolean => loading],
        dateRange: [
            (s) => [s.dateFilter],
            (dateFilter): { date_from: string | null; date_to: string | null } => {
                const dateFromDayjs = dateStringToDayJs(dateFilter.dateFrom)
                const dateToDayjs = dateFilter.dateTo ? dateStringToDayJs(dateFilter.dateTo) : null

                return {
                    date_from: dateFromDayjs?.format('YYYY-MM-DD') ?? dayjs().subtract(7, 'day').format('YYYY-MM-DD'),
                    date_to: dateToDayjs?.format('YYYY-MM-DD') ?? null,
                }
            },
        ],

        overviewQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType],
            (dateRange, endpointFilter, materializationType): EndpointsUsageOverviewQuery => ({
                kind: NodeKind.EndpointsUsageOverviewQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                compareFilter: { compare: true },
            }),
        ],

        requestsTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'requests',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        bytesReadTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'bytes_read',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        cpuSecondsTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'cpu_seconds',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        queryDurationTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'query_duration',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        errorRateTrendsQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType, s.interval, s.breakdownBy],
            (dateRange, endpointFilter, materializationType, interval, breakdownBy): EndpointsUsageTrendsQuery => ({
                kind: NodeKind.EndpointsUsageTrendsQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                metric: 'error_rate',
                interval,
                breakdownBy: breakdownBy ?? undefined,
            }),
        ],

        endpointTableQuery: [
            (s) => [s.dateRange, s.endpointFilter, s.materializationType],
            (dateRange, endpointFilter, materializationType): EndpointsUsageTableQuery => ({
                kind: NodeKind.EndpointsUsageTableQuery,
                dateRange,
                endpointNames: endpointFilter.length > 0 ? endpointFilter : undefined,
                materializationType,
                breakdownBy: EndpointsUsageBreakdown.Endpoint,
                orderBy: ['requests', 'DESC'],
                limit: 100,
            }),
        ],
    }),

    tabAwareActionToUrl(({ values }) => {
        const actionToUrl = ({
            dateFilter = values.dateFilter,
            endpointFilter = values.endpointFilter,
            materializationType = values.materializationType,
            interval = values.interval,
            breakdownBy = values.breakdownBy,
        }): [string, Record<string, any> | undefined, string | undefined] | undefined => {
            const { dateFrom, dateTo } = dateFilter
            const searchParams = { ...router.values.searchParams }

            if (dateFrom !== INITIAL_DATE_FROM) {
                searchParams.dateFrom = dateFrom
            } else {
                delete searchParams.dateFrom
            }

            if (dateTo !== INITIAL_DATE_TO) {
                searchParams.dateTo = dateTo
            } else {
                delete searchParams.dateTo
            }

            if (endpointFilter.length > 0) {
                searchParams.endpointFilter = endpointFilter.join(',')
            } else {
                delete searchParams.endpointFilter
            }

            if (materializationType !== null) {
                searchParams.materializationType = materializationType
            } else {
                delete searchParams.materializationType
            }

            if (interval !== INITIAL_INTERVAL) {
                searchParams.interval = interval
            } else {
                delete searchParams.interval
            }

            if (breakdownBy !== null) {
                searchParams.breakdownBy = breakdownBy
            } else {
                delete searchParams.breakdownBy
            }

            return [router.values.location.pathname, searchParams, router.values.location.hash]
        }

        return {
            setDates: actionToUrl,
            setEndpointFilter: actionToUrl,
            setMaterializationType: actionToUrl,
            setInterval: actionToUrl,
            setBreakdownBy: actionToUrl,
        }
    }),

    tabAwareUrlToAction(({ actions }) => ({
        [urls.endpointsUsage()]: (_, searchParams) => {
            const { dateFrom, dateTo, endpointFilter, materializationType, interval, breakdownBy } = searchParams
            actions.setDates(dateFrom ?? INITIAL_DATE_FROM, dateTo ?? INITIAL_DATE_TO)
            actions.setEndpointFilter(endpointFilter ? endpointFilter.split(',') : [])
            actions.setMaterializationType(materializationType ?? null)
            actions.setInterval(interval ?? INITIAL_INTERVAL)
            actions.setBreakdownBy(breakdownBy ?? null)
        },
    })),
])

import typing
from abc import ABC
from datetime import datetime
from typing import Union, cast

from posthog.schema import EndpointsUsageOverviewQuery, EndpointsUsageTableQuery, EndpointsUsageTrendsQuery

from posthog.hogql import ast

from posthog.hogql_queries.query_runner import AnalyticsQueryResponseProtocol, AnalyticsQueryRunner
from posthog.hogql_queries.utils.query_date_range import QueryDateRange
from posthog.models.filters.mixins.utils import cached_property

EndpointsUsageQueryNode = Union[
    EndpointsUsageOverviewQuery,
    EndpointsUsageTableQuery,
    EndpointsUsageTrendsQuery,
]

EAR = typing.TypeVar("EAR", bound=AnalyticsQueryResponseProtocol)


def safe_float(val: typing.Any) -> float:
    """Convert value to float, handling None and other edge cases."""
    if val is None:
        return 0.0
    try:
        return float(val)
    except (TypeError, ValueError):
        return 0.0


class EndpointsUsageQueryRunner(AnalyticsQueryRunner[EAR], ABC):
    """Base class for Endpoints usage queries.

    Queries the query_log table for endpoint execution metrics, filtering
    specifically for endpoint executions (not general API usage).
    """

    query: EndpointsUsageQueryNode
    query_type: type[EndpointsUsageQueryNode]

    @cached_property
    def query_date_range(self) -> QueryDateRange:
        return QueryDateRange(
            date_range=self.query.dateRange,
            team=self.team,
            interval=None,
            now=datetime.now(),
        )

    def _get_base_where_conditions(self) -> list[ast.Expr]:
        """Build base WHERE conditions for endpoint queries.

        Filters for:
        - Personal API key requests only (external API calls, not app usage)
        - Endpoint executions only (identified by having a non-empty name field)
        - Date range
        """
        conditions: list[ast.Expr] = []

        # Only include requests made via personal API keys (external API calls)
        # This excludes executions from the app itself
        conditions.append(
            ast.CompareOperation(
                op=ast.CompareOperationOp.Eq,
                left=ast.Field(chain=["is_personal_api_key_request"]),
                right=ast.Constant(value=True),
            )
        )

        # Filter for endpoint executions only
        # Endpoint executions are identified by having a non-empty lc_request_name.
        # The 'name' field in HogQL maps to lc_request_name in the underlying table.
        # Non-endpoint queries (like regular HogQL queries) have empty/null names.
        conditions.append(
            ast.Call(
                name="isNotNull",
                args=[ast.Field(chain=["name"])],
            )
        )
        conditions.append(
            ast.CompareOperation(
                op=ast.CompareOperationOp.NotEq,
                left=ast.Field(chain=["name"]),
                right=ast.Constant(value=""),
            )
        )

        conditions.append(
            ast.Call(
                name="match",
                args=[
                    ast.Field(chain=["query_log", "endpoint"]),
                    ast.Constant(value=r"^/api/(environments|projects)/[0-9]+/endpoints/[^/]+/run/?$"),
                ],
            )
        )

        # Date range filter
        if self.query_date_range.date_from():
            conditions.append(
                ast.CompareOperation(
                    op=ast.CompareOperationOp.GtEq,
                    left=ast.Field(chain=["event_date"]),
                    right=ast.Constant(value=self.query_date_range.date_from()),
                )
            )
        if self.query_date_range.date_to():
            conditions.append(
                ast.CompareOperation(
                    op=ast.CompareOperationOp.LtEq,
                    left=ast.Field(chain=["event_date"]),
                    right=ast.Constant(value=self.query_date_range.date_to()),
                )
            )

        # Add endpoint names filter if specified
        endpoint_names_filter = self._get_endpoint_names_filter()
        if endpoint_names_filter:
            conditions.append(endpoint_names_filter)

        # Add materialization type filter if specified
        materialization_filter = self._get_materialization_filter()
        if materialization_filter:
            conditions.append(materialization_filter)

        return conditions

    def _get_endpoint_names_filter(self) -> ast.Expr | None:
        """Filter to specific endpoints if specified."""
        endpoint_names = getattr(self.query, "endpointNames", None)
        if not endpoint_names:
            return None

        # Create OR condition to match both regular and materialized names
        name_conditions = []
        for name in endpoint_names:
            name_conditions.append(
                ast.CompareOperation(
                    op=ast.CompareOperationOp.Eq,
                    left=ast.Field(chain=["name"]),
                    right=ast.Constant(value=name),
                )
            )
            # Also match materialized version
            name_conditions.append(
                ast.CompareOperation(
                    op=ast.CompareOperationOp.Eq,
                    left=ast.Field(chain=["name"]),
                    right=ast.Constant(value=f"{name}_materialized"),
                )
            )

        return ast.Or(exprs=cast(list[ast.Expr], name_conditions))

    def _get_materialization_filter(self) -> ast.Expr | None:
        """Filter by materialization type if specified."""
        from posthog.schema import MaterializationType

        mat_type = getattr(self.query, "materializationType", None)
        if mat_type is None:
            return None

        if mat_type == MaterializationType.MATERIALIZED:
            # Name ends with "_materialized"
            return ast.CompareOperation(
                op=ast.CompareOperationOp.Like,
                left=ast.Field(chain=["name"]),
                right=ast.Constant(value="%_materialized"),
            )
        elif mat_type == MaterializationType.INLINE:
            return ast.Not(
                expr=ast.CompareOperation(
                    op=ast.CompareOperationOp.Like,
                    left=ast.Field(chain=["name"]),
                    right=ast.Constant(value="%_materialized"),
                )
            )
        else:
            # Unknown or None value, no filter
            return None

    def _get_endpoint_name_expression(self) -> ast.Expr:
        """Get an expression that strips '_materialized' suffix from endpoint names.

        This normalizes endpoint names so we can group materialized and non-materialized
        executions of the same endpoint together.
        """
        return ast.Call(
            name="replaceRegexpOne",
            args=[
                ast.Field(chain=["name"]),
                ast.Constant(value="_materialized$"),
                ast.Constant(value=""),
            ],
        )

    def _get_is_materialized_expression(self) -> ast.Expr:
        """Get an expression that returns whether this was a materialized execution."""
        return ast.Call(
            name="endsWith",
            args=[
                ast.Field(chain=["name"]),
                ast.Constant(value="_materialized"),
            ],
        )

    def _get_breakdown_expression(
        self, breakdown: typing.Any, default_alias: str = "breakdown"
    ) -> tuple[ast.Expr, str]:
        """Get the expression and alias for a breakdown column.

        Shared method used by both Trends and Table runners.
        """
        from posthog.schema import EndpointsUsageBreakdown

        if breakdown == EndpointsUsageBreakdown.ENDPOINT:
            return self._get_endpoint_name_expression(), default_alias

        elif breakdown == EndpointsUsageBreakdown.MATERIALIZATION_TYPE:
            return (
                ast.Call(
                    name="if",
                    args=[
                        self._get_is_materialized_expression(),
                        ast.Constant(value="Materialized execution"),
                        ast.Constant(value="Direct execution"),
                    ],
                ),
                default_alias,
            )

        elif breakdown == EndpointsUsageBreakdown.API_KEY:
            return ast.Field(chain=["api_key_label"]), default_alias

        elif breakdown == EndpointsUsageBreakdown.STATUS:
            return self._get_status_expression(), default_alias

        else:
            # Default to endpoint breakdown
            return self._get_endpoint_name_expression(), default_alias

    def _get_status_expression(self) -> ast.Expr:
        """Get an expression that returns 'success' or 'error' based on exception_code."""
        return ast.Call(
            name="if",
            args=[
                ast.CompareOperation(
                    op=ast.CompareOperationOp.Eq,
                    left=ast.Field(chain=["exception_code"]),
                    right=ast.Constant(value=0),
                ),
                ast.Constant(value="success"),
                ast.Constant(value="error"),
            ],
        )

    def _get_error_rate_expression(self) -> ast.Expr:
        """Get an expression for calculating error rate (ratio of failed requests)."""
        return ast.ArithmeticOperation(
            op=ast.ArithmeticOperationOp.Div,
            left=ast.Call(
                name="countIf",
                args=[
                    ast.CompareOperation(
                        op=ast.CompareOperationOp.NotEq,
                        left=ast.Field(chain=["exception_code"]),
                        right=ast.Constant(value=0),
                    )
                ],
            ),
            right=ast.Call(name="count", args=[]),
        )

    def _get_cpu_seconds_expression(self) -> ast.Expr:
        """Get an expression for CPU seconds (converted from microseconds)."""
        return ast.ArithmeticOperation(
            op=ast.ArithmeticOperationOp.Div,
            left=ast.Call(name="sum", args=[ast.Field(chain=["cpu_microseconds"])]),
            right=ast.Constant(value=1000000),
        )

    def _get_bytes_read_expression(self) -> ast.Expr:
        """Get an expression for total bytes read."""
        return ast.Call(name="sum", args=[ast.Field(chain=["read_bytes"])])

    def _get_requests_count_expression(self) -> ast.Expr:
        """Get an expression for request count."""
        return ast.Call(name="count", args=[])

    def _get_avg_latency_expression(self) -> ast.Expr:
        """Get an expression for average query duration in ms."""
        return ast.Call(name="avg", args=[ast.Field(chain=["query_duration_ms"])])

    def _get_p95_latency_expression(self) -> ast.Expr:
        """Get an expression for 95th percentile query duration in ms."""
        return ast.Call(
            name="quantile",
            params=[ast.Constant(value=0.95)],
            args=[ast.Field(chain=["query_duration_ms"])],
        )

    def _get_materialized_count_expression(self) -> ast.Expr:
        """Get an expression for count of materialized requests."""
        return ast.Call(
            name="countIf",
            args=[self._get_is_materialized_expression()],
        )

    def _get_inline_count_expression(self) -> ast.Expr:
        """Get an expression for count of inline (non-materialized) requests."""
        return ast.Call(
            name="countIf",
            args=[ast.Not(expr=self._get_is_materialized_expression())],
        )

