1	import { dayjs, Dayjs } from 'lib/dayjs'
2	
3	import { IntervalType } from '~/types'
4	
5	interface CreateXAxisTickCallbackArgs {
6	    interval?: IntervalType
7	    allDays: (string | number)[]
8	    timezone: string
9	}
10	
11	type TickMode =
12	    | { type: 'month' }
13	    | { type: 'day' }
14	    | { type: 'monthly'; visibleBoundaries: Set<number> }
15	    | { type: 'hourly' }
16	    | { type: 'hourly-multi-day'; step: number }
17	
18	export function createXAxisTickCallback({
19	    interval,
20	    allDays,
21	    timezone,
22	}: CreateXAxisTickCallbackArgs): (value: string | number, index: number) => string | null {
23	    if (allDays.length === 0 || typeof allDays[0] !== 'string') {
24	        return (value) => String(value)
25	    }
26	
27	    const parsedDates = allDays.map((d) => parseDateForAxis(String(d), timezone))
28	    const first = parsedDates[0]
29	    const last = parsedDates[parsedDates.length - 1]
30	
31	    if (!first?.isValid() || !last?.isValid()) {
32	        return (value) => String(value)
33	    }
34	
35	    const resolvedInterval = interval ?? inferInterval(parsedDates)
36	    const mode = pickMode(resolvedInterval, parsedDates, first, last)
37	
38	    return (_value: string | number, index: number): string | null => {
39	        const date = parsedDates[index]
40	        if (!date?.isValid()) {
41	            return String(_value)
42	        }
43	
44	        if (!isTickVisible(mode, date, index)) {
45	            return null
46	        }
47	
48	        return formatTick(mode, date, index)
49	    }
50	}
51	
52	/** Parse a date string as a wall-clock time in the given timezone.
53	 *
54	 * All strings from ClickHouse — both datetime ("2026-03-08 14:00:00") and
55	 * date-only ("2026-03-08") — already have wall-clock digits in the project
56	 * timezone because ClickHouse applies toTimeZone before truncation. */
57	export function parseDateForAxis(dateStr: string, timezone: string): Dayjs {
58	    const hasTime = dateStr.includes(' ') || dateStr.includes('T')
59	    try {
60	        // Parse as UTC so the result is browser-timezone-independent.
61	        // (dayjs.tz(string, tz) goes through new Date() which uses the
62	        // browser's local timezone and can shift dates during DST.)
63	        const utc = hasTime ? dayjs.utc(dateStr) : dayjs.utc(dateStr + ' 00:00:00')
64	        // keepLocalTime: true preserves the wall-clock digits while
65	        // attaching the project timezone — no conversion arithmetic.
66	        return utc.isValid() ? utc.tz(timezone, true) : dayjs(null)
67	    } catch {
68	        return dayjs(null)
69	    }
70	}
71	
72	function pickMode(interval: IntervalType, parsedDates: Dayjs[], first: Dayjs, last: Dayjs): TickMode {
73	    const spanMonths = (last.year() - first.year()) * 12 + last.month() - first.month()
74	    const spanDays = last.diff(first, 'day')
75	
76	    if (interval === 'month') {
77	        return { type: 'month' }
78	    }
79	    if ((interval === 'day' || interval === 'week') && spanMonths >= 3) {
80	        return { type: 'monthly', visibleBoundaries: buildVisibleBoundaries(parsedDates) }
81	    }
82	    if (interval === 'day' || interval === 'week') {
83	        return { type: 'day' }
84	    }
85	    if (spanDays >= 2) {
86	        const step = spanDays <= 3 ? 6 : spanDays <= 7 ? 12 : 24
87	        return { type: 'hourly-multi-day', step }
88	    }
89	    return { type: 'hourly' }
90	}
91	
92	function isTickVisible(mode: TickMode, date: Dayjs, index: number): boolean {
93	    switch (mode.type) {
94	        case 'monthly':
95	            return mode.visibleBoundaries.has(index)
96	        case 'hourly-multi-day':
97	            return index === 0 || date.hour() % mode.step === 0
98	        default:
99	            return true
100	    }
101	}
102	
103	function formatTick(mode: TickMode, date: Dayjs, index: number): string {
104	    switch (mode.type) {
105	        case 'month':
106	        case 'monthly':
107	            return formatMonthLabel(date)
108	        case 'day':
109	            return date.date() === 1 ? formatMonthLabel(date) : date.format('MMM D')
110	        case 'hourly-multi-day':
111	            return date.hour() === 0 || index === 0 ? date.format('MMM D') : date.format('HH:mm')
112	        case 'hourly':
113	            return date.format('HH:mm')
114	    }
115	}
116	
117	function formatMonthLabel(date: Dayjs): string {
118	    if (date.month() === 0) {
119	        return String(date.year())
120	    }
121	    return date.format('MMMM')
122	}
123	
124	function inferInterval(parsedDates: Dayjs[]): IntervalType {
125	    if (parsedDates.length < 2) {
126	        return 'day'
127	    }
128	    const diffHours = parsedDates[1].diff(parsedDates[0], 'hour')
129	    if (diffHours < 1) {
130	        return 'minute'
131	    }
132	    if (diffHours < 24) {
133	        return 'hour'
134	    }
135	    const diffDays = parsedDates[1].diff(parsedDates[0], 'day')
136	    if (diffDays >= 25) {
137	        return 'month'
138	    }
139	    if (diffDays >= 5) {
140	        return 'week'
141	    }
142	    return 'day'
143	}
144	
145	function buildVisibleBoundaries(parsedDates: Dayjs[]): Set<number> {
146	    const boundaries: number[] = []
147	    for (let i = 0; i < parsedDates.length; i++) {
148	        const prev = i > 0 ? parsedDates[i - 1] : null
149	        if (!prev || prev.month() !== parsedDates[i].month()) {
150	            boundaries.push(i)
151	        }
152	    }
153	
154	    const visible = new Set(boundaries)
155	    const minGap = Math.max(3, Math.floor(parsedDates.length / 10))
156	
157	    if (boundaries.length >= 2 && boundaries[1] - boundaries[0] < minGap) {
158	        visible.delete(boundaries[0])
159	    }
160	    if (boundaries.length >= 2 && boundaries[boundaries.length - 1] - boundaries[boundaries.length - 2] < minGap) {
161	        visible.delete(boundaries[boundaries.length - 1])
162	    }
163	
164	    return visible
165	}
